#!/usr/bin/env python3
"""
bootstrap_pulldown_selector.py -- Cell type -> pulldown design pipeline.

Deploys:
  glycan/pulldown_selector.py         -- cell type -> lectin -> sugar -> linker
  glycan/tests/test_pulldown_selector.py -- 29 tests

Depends on: bootstrap_click_site_predictor.py + bootstrap_bead_linker_design.py.
No file conflicts with prior bootstraps.

Test: python -m pytest glycan/tests/test_pulldown_selector.py -v
"""

import base64, os, sys

FILES = {
    'glycan/pulldown_selector.py': '',
    'glycan/tests/test_pulldown_selector.py': '',
}


def find_root():
    d = os.path.abspath(os.getcwd())
    for _ in range(5):
        if os.path.isfile(os.path.join(d, 'core', 'universal_schema.py')):
            return d
        parent = os.path.dirname(d)
        if parent == d:
            break
        d = parent
    d = os.path.abspath(os.path.join(os.getcwd(), '..'))
    if os.path.isfile(os.path.join(d, 'core', 'universal_schema.py')):
        return d
    print('ERROR: Cannot find MABE repo root (need core/universal_schema.py).')
    sys.exit(1)


def main():
    root = find_root()
    print(f'MABE root: {root}')
    print()
    for relpath, b64data in FILES.items():
        fullpath = os.path.join(root, relpath)
        os.makedirs(os.path.dirname(fullpath), exist_ok=True)
        content = base64.b64decode(b64data).decode('utf-8')
        with open(fullpath, 'w', encoding='utf-8') as f:
            f.write(content)
        print(f'  written: {relpath}')
    print()
    print(f'Bootstrap complete: {len(FILES)} files written.')
    print('Requires: bootstrap_click_site_predictor.py + bootstrap_bead_linker_design.py applied first.')
    print('Run: python -m pytest glycan/tests/test_pulldown_selector.py -v')


if __name__ == '__main__':
    main()